103	    // 60 + 60 = 120 base + 12 first-insurance = 132 + 5 fee = 137
104	    expect(out).toEqual({ results: [{ premium: 137 }] });
105	  });
106	
107	  // === Cursed surcharge ===
108	  it("cursed sword (steel, enchantment 3) for newcomer → 165 G (integration example)", () => {
