125	  it("sword enchantment 4 → no high-enchantment surcharge", () => {
126	    const out = runScenario({
127	      customer: { yearsWithMHPCO: 0 },
128	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }] }],
129	    });
130	    expect(out).toEqual({ results: [{ premium: 115 }] });
