132	
133	  // === Loyalty discount ===
134	  it("customer with exactly 2 years → loyalty discount applies", () => {
135	    const out = runScenario({
136	      customer: { yearsWithMHPCO: 2 },
137	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
