142	  it.todo("customer with 1 year → no loyalty discount");
143	
144	  // === Follow-up contract discount ===
145	  it.todo("second quote in scenario receives 15 % follow-up discount");
146	
147	  // === Modifier scope on multi-item policies ===
148	  it.todo("cursed sword + plain amulet → 210 G before further modifiers and fee (item-scoped curse)");
149	
150	  // === Integration: long-standing customer's second contract ===
151	  it.todo("3-yr customer's 2nd contract, cursed sword enchantment 7 → 160 G");
152	
153	  // === Rounding ===
154	  it.todo("premium that yields 197.5 G → rounded up to 198 G");
155	  it.todo("payout that yields 350.5 G → rounded down to 350 G");
156	
157	  // === Claim: standard reimbursement ===
158	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G");
159	  it.todo("damage to rune (no enchantment, no material), damage 200 G → payout 100 G");
160	
161	  // === Claim: high-enchantment clause ===
162	  it.todo("dragon sword ench 8, damage 1000 G → payout 400 G");
163	  it.todo("dragon sword ench 9, damage 1000 G → payout 400 G (50 % then deductible)");
164	
165	  // === Claim: dragon material clause ===
166	  it.todo("dragon sword ench 5, damage 800 G → payout 700 G (only dragon clause)");
167	
168	  // === Claim: high-enchantment alone ===
169	  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50 % then deductible)");
170	
171	  // === Claim: deductible per damage event ===
172	  it.todo("dragon attack on sword (500) and amulet (300) → payout 600 G (deductible per item)");
173	
174	  // === Multiple items of the same type ===
175	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
176	  it.todo("two sword damages on a two-sword policy → each damage gets own deductible");
177	  it.todo("more damage entries than insured items of that type → rejected (throws)");
178	
179	  // === Cap exhaustion ===
180	  it.todo("cursed sword cap = 2000 G (cap based on unmodified insurance value)");
181	  it.todo("sword + 3 runes → insurance sum 1750 G (block does not affect insurance sum)");
182	  it.todo("two successive 1500 G claims on sword: first 1400 G remaining 600, second 600 remaining 0");
183	
184	  // === Edge cases ===
185	  it.todo("unknown item type in quote → throws / non-zero exit");
186	  it.todo("claim with damage to item not in policy → throws / non-zero exit");
187	  it.todo("claim with negative damage amount → throws / non-zero exit");
188	});
