1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const BLOCK_SIZE = 3;
9	const BLOCK_PREMIUM = 60;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	type Item = { type: string; cursed?: boolean; enchantment?: number };
23	type QuoteStep = { op: "quote"; items: Array<Item> };
24	type Customer = { yearsWithMHPCO: number };
25	type Scenario = { customer: Customer; steps: Array<QuoteStep> };
26	
27	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
28	
29	const countByType = (items: Item[]): Record<string, number> => {
30	  const counts: Record<string, number> = {};
31	  for (const item of items) {
32	    counts[item.type] = (counts[item.type] ?? 0) + 1;
33	  }
34	  return counts;
35	};
36	
37	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
38	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
39	
40	const subtotalForType = (type: string, count: number): number =>
41	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
42	
43	const policyBaseFor = (items: Item[]): number =>
44	  sum(Object.entries(countByType(items)).map(([type, count]) => subtotalForType(type, count)));
45	
46	const isHighlyEnchanted = (item: Item): boolean =>
47	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
48	
49	const surchargeRate = (item: Item): number =>
50	  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
51	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
52	
53	const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);
54	
55	const quotePremium = (step: QuoteStep, customer: Customer): number => {
56	  const policyBase = policyBaseFor(step.items);
57	  const itemSurchargesTotal = sum(step.items.map(itemSurcharge));
58	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
59	  const loyaltyDiscount = customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
60	  return Math.ceil(policyBase + itemSurchargesTotal + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE);
61	};
62	
63	export const runScenario = (input: unknown): unknown => {
64	  const scenario = input as Scenario;
65	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step, scenario.customer) }));
66	  return { results };
67	};
