const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const loyaltyDiscountFor = (policyBase: number, customer: Customer): number =>
  qualifiesForLoyaltyDiscount(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;

const quotePremium = (step: QuoteStep, customer: Customer): number => {
  const policyBase = policyBaseFor(step.items);
  const itemSurchargesTotal = sum(step.items.map(itemSurcharge));
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount = loyaltyDiscountFor(policyBase, customer);
  return Math.ceil(policyBase + itemSurchargesTotal + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE);
};
